package funck

import "github.com/silasdev78/silas-code-inspector/internal/domain"

func Patterns() []domain.Pattern {
	return []domain.Pattern{
		{ID: "FUNC-001", Title: "Missing seqno check in recv_external", Regex: `recv_external\s*\(`, Severity: domain.SeverityCritical, Description: "External message without seqno allows replay attacks.", Recommendation: "Add require_seqno() check in recv_external."},
		{ID: "FUNC-002", Title: "Unchecked sender in recv_external", Regex: `recv_external\s*\(`, Severity: domain.SeverityHigh, Description: "No sender verification in external handler.", Recommendation: "Check sender_address() against owner."},
		{ID: "FUNC-003", Title: "Unprotected selfdestruct", Regex: `selfdestruct\s*\(`, Severity: domain.SeverityCritical, Description: "selfdestruct without access control.", Recommendation: "Wrap in throw_unless with admin check."},
		{ID: "FUNC-004", Title: "Integer overflow/underflow", Regex: `\+\s*1|-\s*1`, Severity: domain.SeverityHigh, Description: "Potential overflow in arithmetic operations.", Recommendation: "Use safe math functions."},
		{ID: "FUNC-005", Title: "Hardcoded address", Regex: `"[EQ][a-zA-Z0-9_-]{47,}"`, Severity: domain.SeverityInfo, Description: "Hardcoded address found.", Recommendation: "Use a config constant."},
		{ID: "FUNC-006", Title: "Unbounded loop", Regex: `\bwhile\s*\(`, Severity: domain.SeverityHigh, Description: "Loops without gas limit.", Recommendation: "Add a max iteration guard."},
		{ID: "FUNC-007", Title: "External call in loop", Regex: `\.\s*send_raw_message\s*\(`, Severity: domain.SeverityMedium, Description: "Sending messages in loop drains gas.", Recommendation: "Batch messages or limit iterations."},
		{ID: "FUNC-008", Title: "Missing storage fee consideration", Regex: `set_gas_limits\s*\(`, Severity: domain.SeverityMedium, Description: "No storage fee top-up logic.", Recommendation: "Regularly top-up storage."},
		{ID: "FUNC-009", Title: "Timeout not enforced", Regex: `recv_external\s*\(`, Severity: domain.SeverityLow, Description: "No deadline check.", Recommendation: "Add throw_unless(now() < deadline)."},
		{ID: "FUNC-010", Title: "Uninitialized variable", Regex: `\bvar\s+\w+\s*;`, Severity: domain.SeverityLow, Description: "Variable without initial value.", Recommendation: "Initialize explicitly."},
		{ID: "FUNC-011", Title: "Gas check missing", Regex: `recv_external\s*\(`, Severity: domain.SeverityMedium, Description: "No gas limit check.", Recommendation: "Use accept_message() or set_gas_limit()."},
		{ID: "FUNC-012", Title: "Old compiler pragma", Regex: `#pragma\s+version\s*<`, Severity: domain.SeverityLow, Description: "Outdated compiler version.", Recommendation: "Update to latest FunC compiler."},
		{ID: "FUNC-013", Title: "Signature verification missing", Regex: `recv_external\s*\(`, Severity: domain.SeverityHigh, Description: "No signature check in external.", Recommendation: "Use check_signature()."},
		{ID: "FUNC-014", Title: "Unchecked send_raw_message result", Regex: `send_raw_message\s*\(`, Severity: domain.SeverityMedium, Description: "Result of send_raw_message ignored.", Recommendation: "Check the return value."},
		{ID: "FUNC-015", Title: "Missing state invariant", Regex: `;;\s*invariant`, Severity: domain.SeverityLow, Description: "No invariant comment for state.", Recommendation: "Document state invariants."},
		{ID: "FUNC-016", Title: "Insecure random source", Regex: `\brandom\s*\(`, Severity: domain.SeverityHigh, Description: "Predictable randomness.", Recommendation: "Use commit-reveal or off-chain."},
		{ID: "FUNC-017", Title: "Missing access control modifier", Regex: `global\s+\w+\s+`, Severity: domain.SeverityMedium, Description: "Global variable without access control.", Recommendation: "Limit access with modifiers."},
		{ID: "FUNC-018", Title: "Exposed internal function", Regex: `\bglobal\s+\w+\s*\(`, Severity: domain.SeverityInfo, Description: "Function name suggests internal but is global.", Recommendation: "Make local or document."},
		{ID: "FUNC-019", Title: "Unchecked msg value", Regex: `recv_external\s*\(`, Severity: domain.SeverityLow, Description: "No check on msg_value.", Recommendation: "Add throw_unless(msg_value > 0)."},
		{ID: "FUNC-020", Title: "Missing code upgrade path", Regex: `set_code\s*\(`, Severity: domain.SeverityInfo, Description: "No upgrade mechanism.", Recommendation: "Consider proxy or set_code pattern."},
		{ID: "FUNC-021", Title: "Unhandled bounced messages", Regex: `recv_internal\s*\(\s*0xFFFFFFFF\s*\)`, Severity: domain.SeverityCritical, Description: "Bounced messages not handled.", Recommendation: "Handle bounced flag in recv_internal."},
		{ID: "FUNC-022", Title: "Message race condition", Regex: `send_raw_message\s*\(\s*\w+\s*,\s*\w+\s*,\s*0\s*\)`, Severity: domain.SeverityHigh, Description: "State after send may be inconsistent.", Recommendation: "Use carry-value pattern."},
		{ID: "FUNC-023", Title: "Insufficient balance check", Regex: `balance\s*-\s*\w+`, Severity: domain.SeverityCritical, Description: "Balance subtraction without require.", Recommendation: "Add throw_unless(balance >= amount)."},
		{ID: "FUNC-024", Title: "Division before multiplication", Regex: `\w+\s*/\s*\w+\s*\*`, Severity: domain.SeverityHigh, Description: "Precision loss.", Recommendation: "Multiply first, then divide."},
		{ID: "FUNC-025", Title: "Use of raw slice manipulation", Regex: `slice\s*begin_cell\s*\(`, Severity: domain.SeverityMedium, Description: "Raw slice may cause runtime errors.", Recommendation: "Use safe builders."},
		{ID: "FUNC-026", Title: "Missing impure specifier", Regex: `\b(?:int|cell|slice|tuple)\s+\w+\s*\([^)]*\)\s*(?:impure)?\s*\{`, Severity: domain.SeverityCritical, Description: "Function modifies state or sends message but lacks impure specifier. Compiler may remove calls.", Recommendation: "Add impure specifier to state-changing functions."},
		{ID: "FUNC-027", Title: "raw_reserve before validation", Regex: `raw_reserve\s*\([^)]*\)\s*;`, Severity: domain.SeverityCritical, Description: "Reserve called before validation may lock funds permanently.", Recommendation: "Perform all checks before raw_reserve."},
		{ID: "FUNC-028", Title: "Unvalidated set_data", Regex: `set_data\s*\(\s*\w+\s*\)`, Severity: domain.SeverityCritical, Description: "Storing raw cell without validation can brick the contract.", Recommendation: "Parse and validate cell/slice before set_data."},
		{ID: "FUNC-029", Title: "Silent message failure", Regex: `send_raw_message\s*\([^)]*,\s*0\s*\)`, Severity: domain.SeverityHigh, Description: "Message sent with mode 0 or result unchecked; failure is silent.", Recommendation: "Check return flag or use mode 64 + bounced handler."},
		{ID: "FUNC-030", Title: "Cell depth overflow", Regex: `udict\s*set\b`, Severity: domain.SeverityHigh, Description: "Deep cell trees cause gas explosions or storage fees.", Recommendation: "Limit nesting depth and clean up periodically."},
		{ID: "FUNC-031", Title: "Unsafe raw cell manipulation", Regex: `\bsti\b|\bldu\b|\bstu\b|\bldi\b`, Severity: domain.SeverityHigh, Description: "Direct bit manipulation may corrupt data or cause runtime errors.", Recommendation: "Use Builder/Slice primitives."},
		{ID: "FUNC-032", Title: "Incorrect bounceable flag", Regex: `send_raw_message\s*\([^)]*,\s*(?:64|128)\s*\)`, Severity: domain.SeverityCritical, Description: "Bounceable flag misuse in Jetton/NFT standards may cause loss of assets.", Recommendation: "Follow TEP-74/62 for bounceable flag."},
		{ID: "FUNC-033", Title: "Forward TON without gas pre-check", Regex: `send_raw_message\s*\([^)]*,\s*\d+\s*\)`, Severity: domain.SeverityCritical, Description: "Forwarding value without gas check can drain contract balance.", Recommendation: "Check contract balance and gas costs before forward."},
		{ID: "FUNC-034", Title: "Int as boolean misuse", Regex: `if\s*\(\s*\w+\s*\)`, Severity: domain.SeverityHigh, Description: "Int can be negative; using as boolean may cause unexpected behavior.", Recommendation: "Explicitly check x != 0."},
		{ID: "FUNC-035", Title: "Fake jetton notification", Regex: `transfer_notification`, Severity: domain.SeverityCritical, Description: "Any contract can send fake transfer_notification.", Recommendation: "Check sender wallet code_hash and owner."},
		{ID: "FUNC-036", Title: "Irreversible state change without carry-value", Regex: `send_raw_message\s*\(\s*\w+\s*,\s*\w+\s*,\s*\d+\s*\)`, Severity: domain.SeverityCritical, Description: "State dependency across messages may cause race conditions.", Recommendation: "Use carry-value pattern: include all context in payload."},
		{ID: "FUNC-037", Title: "Unchecked excesses", Regex: `accept_message\s*\(`, Severity: domain.SeverityHigh, Description: "Excesses may not arrive; relying on them causes stuck state.", Recommendation: "Never depend on excesses for critical logic."},
		{ID: "FUNC-038", Title: "Storage fee miscalculation", Regex: `set_gas_limits\s*\([^)]*,\s*\d+\s*\)`, Severity: domain.SeverityHigh, Description: "Low balance + high cell depth may lead to contract deletion.", Recommendation: "Regularly top up storage and calculate fees accurately."},
		{ID: "FUNC-039", Title: "Invalid throw codes", Regex: `throw\s*\(\s*(?:0|1)\s*\)`, Severity: domain.SeverityMedium, Description: "Throw codes 0 and 1 are reserved or ambiguous.", Recommendation: "Use specific error codes >= 2."},
		{ID: "FUNC-040", Title: "Global variable redefinition", Regex: `global\s+\w+\s+\w+\s*;`, Severity: domain.SeverityHigh, Description: "Global redefinition may cause trait-like conflicts.", Recommendation: "Check for naming collisions."},
		{ID: "FUNC-041", Title: "Block dependency for randomness", Regex: `\b(?:now|lt)\s*\(\s*\)`, Severity: domain.SeverityHigh, Description: "now()/lt() are predictable in async model.", Recommendation: "Use nativeRandom with commit-reveal."},
		{ID: "FUNC-042", Title: "Precision loss in math", Regex: `\w+\s*/\s*\w+\s*\*`, Severity: domain.SeverityHigh, Description: "Division before multiplication causes precision loss.", Recommendation: "Multiply first, then divide."},
		{ID: "FUNC-043", Title: "Mutable message parameters", Regex: `in_msg\s*~`, Severity: domain.SeverityMedium, Description: "Modifying incoming message may cause unexpected behavior.", Recommendation: "Copy message parameters before modification."},
		{ID: "FUNC-044", Title: "Missing replay protection", Regex: `recv_external\s*\(`, Severity: domain.SeverityCritical, Description: "External message without seqno+signature allows replay and front-run.", Recommendation: "Add seqno check and signature verification."},
		{ID: "FUNC-045", Title: "Excessive dict storage", Regex: `udict\s*set\b`, Severity: domain.SeverityMedium, Description: "Unbounded dictionaries can explode storage fees.", Recommendation: "Implement cleanup mechanisms."},
		{ID: "FUNC-046", Title: "Raw assembler usage", Regex: `\basm\s*\(|\bnative\s+\w+\s*\(`, Severity: domain.SeverityHigh, Description: "Inline assembly breaks safety guarantees.", Recommendation: "Avoid asm blocks or audit rigorously."},
		{ID: "FUNC-047", Title: "Partial execution inconsistency", Regex: `send_raw_message\s*\(\s*\w+\s*,\s*\w+\s*,\s*2\s*\)`, Severity: domain.SeverityCritical, Description: "State updated in one contract but not another due to partial execution.", Recommendation: "Implement atomic multi-contract updates with reconciliation."},
		{ID: "FUNC-048", Title: "Address validation missing", Regex: `slice_bits\s*\(\s*\w+\s*\)\s*!=\s*267`, Severity: domain.SeverityHigh, Description: "Address not validated may be zero or non-standard.", Recommendation: "Validate address length and chain ID."},
		{ID: "FUNC-049", Title: "Deprecated compiler version", Regex: `#pragma\s+version\s*<\s*0\.4`, Severity: domain.SeverityLow, Description: "Very old compiler version; consider migrating to Tolk.", Recommendation: "Update compiler or migrate to Tolk."},
		{ID: "FUNC-050", Title: "Missing post-condition check", Regex: `throw_unless\s*\([^)]*\)`, Severity: domain.SeverityHigh, Description: "State changes without invariant checks.", Recommendation: "Add require() statements after state modifications."},
	}
}
